 1	import React, { ChangeEvent, FC, ReactNode } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import useLocalStorage from '@kubevirt-utils/hooks/useLocalStorage';
 5	import {
 6	  Divider,
 7	  Split,
 8	  SplitItem,
 9	  Stack,
10	  StackItem,
11	  Switch,
12	  Text,
13	  Toolbar,
14	  ToolbarContent,
15	  TreeViewSearch,
16	} from '@patternfly/react-core';
17	
18	import { HIDE, SHOW, SHOW_EMPTY_PROJECTS_KEY, TREE_VIEW_SEARCH_ID } from '../utils/constants';
19	
20	type TreeViewToolbarProps = {
21	  closeComponent: ReactNode;
22	  isSwitchDisabled: boolean;
23	  onSearch: (event: ChangeEvent<HTMLInputElement>) => void;
24	};
25	
26	const TreeViewToolbar: FC<TreeViewToolbarProps> = ({
27	  closeComponent,
28	  isSwitchDisabled,
29	  onSearch,
30	}) => {
31	  const { t } = useKubevirtTranslation();
32	  const [showEmptyProjects, setShowEmptyProjects] = useLocalStorage(SHOW_EMPTY_PROJECTS_KEY, HIDE);
33	
34	  return (
35	    <Toolbar className="vms-tree-view-toolbar" isSticky>
36	      <ToolbarContent className="vms-tree-view-toolbar-content">
37	        <Stack className="vms-tree-view__toolbar-section" hasGutter>
38	          <StackItem>
39	            <Split>
40	              <SplitItem className="vms-tree-view__search-input" isFilled>
41	                <TreeViewSearch
42	                  id={TREE_VIEW_SEARCH_ID}
43	                  name={TREE_VIEW_SEARCH_ID}
44	                  onSearch={onSearch}
45	                  placeholder={t('Search')}
46	                />
47	              </SplitItem>
48	              <SplitItem className="vms-tree-view__close-container">{closeComponent}</SplitItem>
49	            </Split>
50	          </StackItem>
51	          <Divider />
52	          <StackItem>
53	            <Split>
54	              <SplitItem className="pf-v6-u-ml-md">
55	                <Text>{t('Show only projects with VirtualMachines')}</Text>
56	              </SplitItem>
57	              <SplitItem isFilled />
58	              <Switch
59	                checked={!isSwitchDisabled && showEmptyProjects === HIDE}
60	                className="vms-tree-view__toolbar-switch"
61	                isDisabled={isSwitchDisabled}
62	                isReversed
63	                onChange={(_, checked) => setShowEmptyProjects(checked ? HIDE : SHOW)}
64	              />
65	            </Split>
66	          </StackItem>
67	          <Divider />
68	        </Stack>
69	      </ToolbarContent>
70	    </Toolbar>
71	  );
72	};
73	
74	export default TreeViewToolbar;

